const records = $json.records || [];
const syncRunId = $json.sync_run_id || null;

if (records.length === 0) {
  return [
    {
      json: {
        __empty_batch: true,
        count: 0,
        records: [],
        sync_run_id: syncRunId
      }
    }
  ];
}

return records.map(record => ({
  json: {
    ...record,
    sync_run_id: syncRunId
  }
}));

const syncRunId =
  $json.sync_run_id ??
  $("Postgres Create Company Sync Run").first().json.sync_run_id ??
  null;

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: 0,
      staged_count: 0,
      promoted_count: 0,
      skipped_count: 0,
      error_count: 0
    }
  }
];

const items = $input.all();
if (items.length === 0) {
  return [{ json: { __success_branch: true } }];
}
return items.map(i => ({ json: { ...i.json, __success_branch: true } }));

const allItems = $input.all();

const syncRunItem = allItems.find(i => i.json.sync_run_id !== undefined);
const syncRunId = syncRunItem?.json?.sync_run_id ?? null;

const fetchedCount = Number($("HTTP Request").first().json.count || 0);

const staged = (() => {
  try { return $("Postgres Raw Stage Companies").all().length; }
  catch(e) { return 0; }
})();

const promoted = (() => {
  try {
    return $("Postgres Promote Companies").all().filter(item => {
      const j = item.json || {};
      return !!(j.id || j.erp_sync_id || j.name);
    }).length;
  } catch(e) { return 0; }
})();

const skipped = Math.max(fetchedCount - promoted, 0);

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: fetchedCount,
      staged_count: staged,
      promoted_count: promoted,
      skipped_count: skipped,
      error_count: 0
    }
  }
];
